/**
 * 事件执行工具函数
 */

import type {
  Action,
  ActionResult,
  EventConfig,
  EventContext,
  EventFunctions,
  EventType,
} from './events.types'
import { getActionHandler } from './action-handlers'
import {
  showConfirmDialog as baseShowConfirmDialog,
  showFormDialog as baseShowFormDialog,
} from './dialog-atom'

/**
 * 解析事件类型到 React 事件名称的映射
 */
export const eventTypeToReactEvent: Record<EventType, string> = {
  click: 'onClick',
  doubleClick: 'onDoubleClick',
  mouseEnter: 'onMouseEnter',
  mouseLeave: 'onMouseLeave',
  change: 'onChange',
  submit: 'onSubmit',
  focus: 'onFocus',
  blur: 'onBlur',
  input: 'onInput',
}

/**
 * 解析 React 事件名称到事件类型的映射
 */
export const reactEventToEventType: Record<string, EventType> = {
  onClick: 'click',
  onDoubleClick: 'doubleClick',
  onMouseEnter: 'mouseEnter',
  onMouseLeave: 'mouseLeave',
  onChange: 'change',
  onSubmit: 'submit',
  onFocus: 'focus',
  onBlur: 'blur',
  onInput: 'input',
}

/**
 * 显示二次确认对话框
 */
export function showConfirmDialog(
  confirmConfig?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
): Promise<boolean> {

  return baseShowConfirmDialog(confirmConfig)
}

/**
 * 显示表单对话框
 */
export function showFormDialog(
  fields: any[],
  initialValues?: Record<string, any>,
  title?: string,
  description?: string
): Promise<Record<string, any> | null> {
  return baseShowFormDialog(fields, initialValues, title, description)
}

/**
 * 执行单个动作
 */
export async function executeAction(
  action: Action,
  context: EventContext
): Promise<ActionResult> {

  try {
    // 检查是否需要二次确认
    if (action.confirm) {

      const confirmed = await showConfirmDialog(action.confirm)

      if (!confirmed) {
        return { success: false, error: '用户取消操作' }
      }
    }

    // 检查是否需要延迟执行
    if (action.delay && action.delay > 0) {
      await new Promise((resolve) => setTimeout(resolve, action.delay))
    }

    // 获取动作处理器并执行
    const handler = getActionHandler(action.type)
    const result = await handler(action.params, context)

    return result
  } catch (error) {
    return {
      success: false,
      error: error instanceof Error ? error.message : '执行动作失败',
    }
  }
}

/**
 * 执行事件的所有动作（按顺序）
 */
export async function executeActions(
  actions: Action[],
  context: EventContext
): Promise<ActionResult[]> {
  const results: ActionResult[] = []
  let prevResult: any = undefined

  for (let i = 0; i < actions.length; i++) {
    const action = actions[i]
    const actionContext = {
      ...context,
      prevResult,
    }

    const result = await executeAction(action, actionContext)
    results.push(result)

    // 保存当前结果供下一个动作使用
    if (result.success) {
      prevResult = result.data
    } else {
      // 如果动作执行失败，可以选择停止或继续
      // 这里选择停止执行后续动作
      break
    }
  }

  return results
}

/**
 * 创建事件处理器函数
 */
export function createEventHandler(
  eventType: EventType,
  actions: Action[],
  onLoadingChange?: (loading: boolean) => void,
  onError?: (error: string) => void,
  eventFunctions?: EventFunctions
) {
  return async (e?: React.SyntheticEvent) => {
    if (!actions || actions.length === 0) {
      return
    }

    // 阻止默认行为（如表单提交）
    e?.preventDefault()

    onLoadingChange?.(true)

    try {
      const context: EventContext = {
        eventType,
        eventParams: e,
        eventFunctions,
      }

      const results = await executeActions(actions, context)

      // 检查是否有失败的执行
      const hasFailure = results.some((r) => !r.success)
      if (hasFailure) {
        const lastError = results.reverse().find((r) => r.error)?.error
        onError?.(lastError || '事件执行失败')
      }
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : '未知错误'
      onError?.(errorMessage)
    } finally {
      onLoadingChange?.(false)
    }
  }
}

/**
 * 解析事件配置，生成事件处理器映射
 */
export function parseEventConfig(
  config: EventConfig,
  eventFunctions?: EventFunctions
): Record<EventType, (e?: React.SyntheticEvent) => Promise<void>> {
  const handlers: Record<
    EventType,
    (e?: React.SyntheticEvent) => Promise<void>
  > = {} as any

  for (const [eventType, actions] of Object.entries(config)) {
    if (actions && actions.length > 0) {
      handlers[eventType as EventType] = createEventHandler(
        eventType as EventType,
        actions,
        undefined,
        undefined,
        eventFunctions
      )
    }
  }

  return handlers
}

/**
 * 事件和动作类型定义
 */

/** 事件类型 */
export type EventType =
  | 'click' // 单击
  | 'doubleClick' // 双击
  | 'mouseEnter' // 移入
  | 'mouseLeave' // 移出
  | 'change' // 值变化
  | 'submit' // 表单提交
  | 'focus' // 聚焦
  | 'blur' // 失焦
  | 'input' // 输入

/** 动作类型 */
export type ActionType =
  | 'pageJump' // 页面跳转
  | 'changeVar' // 修改变量
  | 'changeTableData' // 修改表数据
  | 'changeDict' // 修改数据字典
  | 'changeDataPoint' // 修改数据点配置
  | 'changeSystemSetting' // 修改系统设置
  | 'changeUser' // 修改用户
  | 'callFlow' // 调用流程
  | 'executeCommand' // 执行指令
  | 'sendRequest' // 发送请求

/** 值类型 - 变量值或组件值 */
export type ValueType = 'varValue' | 'comValue'

/** 执行结果消息配置 */
export interface ResultMessage {
  /** 成功提示 */
  successMess?: boolean
  /** 成功显示时常（秒） */
  successTime?: number
  /** 成功显示内容 */
  successContent?: string
  /** 失败提示 */
  errorMess?: boolean
  /** 失败显示时常（秒） */
  errorTime?: number
  /** 失败显示内容 */
  errorContent?: string
}

/** 打开方式 */
export type OpenWay = '_blank' | '_self' | '_parent' | '_top'

/** 权限类型 */
export type PermissionType = 'users' | 'roles'

/** 页面跳转动作参数 */
export interface PageJumpParams {
  url: string
  openWay?: OpenWay
  showMessage?: boolean
  permission?: PermissionType
  users?: string[]
  roles?: string[]
}

/** 修改变量动作参数 */
export interface ChangeVarParams extends ResultMessage {
  var: Record<string, any>
  varValue?: Record<string, any>
}

/** 修改表数据动作参数 */
export interface ChangeTableDataParams extends ResultMessage {
  table: Record<string, any>
  data: Record<string, any>
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: Array<{
    key: string
    value: string
  }>
}

/** 修改数据字典动作参数 */
export interface ChangeDictParams extends ResultMessage {
  systemVar: Record<string, any>
  value?: Record<string, any>
}

/** 数据点属性 */
export interface DataPointProperty {
  /** 资产数据点 */
  recordDataPoint?: {
    tableId: string
    tableDataId: string
    tagId: string
  }
  /** 模型数据点 */
  tableDataPoint?: {
    tableId: string
    tagId: string
  }
  /** 要更新的属性键 */
  key: string
  /** 要设置的值 */
  value?: any
}

/** 修改数据点配置动作参数 */
export interface ChangeDataPointParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  /** 数据点配置数组 */
  dataPointMulti: DataPointProperty[]
}

/** 字段和值 */
export interface FieldValuePair {
  key: string
  value: string
}

/** 修改系统设置动作参数 */
export interface ChangeSystemSettingParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: FieldValuePair[]
}

/** 修改用户动作参数 */
export interface ChangeUserParams extends ResultMessage {
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  fields?: string[]
  nodeProp?: FieldValuePair[]
}

/** 调用流程动作参数 */
export interface CallFlowParams extends ResultMessage {
  flow: Record<string, any>
  /** 触发时修改（弹出表单） */
  showForm?: boolean
  params?: Record<string, any>
}

/** 动作基础接口 */
export interface Action {
  /** 动作类型 */
  type: ActionType
  /** 动作参数 */
  params: any
  /** 是否需要二次确认 */
  confirm?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
  /** 延迟执行（毫秒） */
  delay?: number
}

/** 事件配置 */
export interface EventConfig {
  [eventType: string]: Action[]
}

/** 事件函数集合 */
export interface EventFunctions {
  /** 设置页面变量 */
  setPageVar?: (path: string, value: any) => void
}

/** 事件执行上下文 */
export interface EventContext {
  /** 事件源组件 */
  component?: React.ComponentType<any>
  /** 当前事件类型 */
  eventType: EventType
  /** 事件触发参数（如事件对象） */
  eventParams?: any
  /** 前一个动作的执行结果 */
  prevResult?: any
  /** 事件函数集合 */
  eventFunctions?: EventFunctions
}

/** 动作执行结果 */
export interface ActionResult {
  /** 是否成功 */
  success: boolean
  /** 返回数据 */
  data?: any
  /** 错误信息 */
  error?: string
}

/** 动作处理器 */
export type ActionHandler = (
  params: any,
  context: EventContext
) => Promise<ActionResult> | ActionResult

/** 事件处理器返回值 */
export interface EventHandlerReturn {
  /** 事件处理函数 */
  handler: (e?: React.SyntheticEvent) => void | Promise<void>
  /** 是否正在执行 */
  loading: boolean
  /** 执行错误 */
  error: string | null
}

/** 事件配置对象 */
export interface EventsReturn extends Partial<Record<EventType, (e?: React.SyntheticEvent) => void | Promise<void>>> {
  /** 各事件的处理器 */
  [key: string]: ((e?: React.SyntheticEvent) => void | Promise<void>) | EventConfig | undefined
  /** 事件配置原始数据 */
  config: EventConfig
}

/**
 * 动作处理器 - 索引文件
 *
 * 导出所有动作处理器
 */

import { atom } from 'jotai'
import type { ActionHandler } from './events.types'

// 表单字段类型
export type FormField = {
  name: string
  label: string
  type?: 'text' | 'number' | 'boolean' | 'select' | 'textarea'
  defaultValue?: any
  required?: boolean
  placeholder?: string
  options?: { label: string; value: string | number }[]
  validate?: (value: any) => string | null
}

// ============== 对话框状态 atoms ==============

/**
 * 确认对话框配置
 */
export interface ConfirmDialogConfig {
  title?: string
  message?: string
  confirmText?: string
  cancelText?: string
}

/**
 * 表单对话框配置
 */
export interface FormDialogConfig {
  title?: string
  description?: string
  fields: FormField[]
  confirmText?: string
  cancelText?: string
  initialValues?: Record<string, any>
}

/**
 * 确认对话框状态 atom
 */
export const confirmDialogAtom = atom<ConfirmDialogConfig | null>(null)

/**
 * 表单对话框状态 atom
 */
export const formDialogAtom = atom<FormDialogConfig | null>(null)

/**
 * 确认对话框的 resolve 函数 atom
 */
export const confirmDialogResolveAtom = atom<((value: boolean) => void) | null>(null)

/**
 * 表单对话框的 resolve 函数 atom
 */
export const formDialogResolveAtom = atom<((value: any) => void) | null>(null)

// ============== 导入所有处理器 ==============

export { pageJumpHandler } from './handlers/pageJumpHandler'
export { changeVarHandler } from './handlers/changeVarHandler'
export { changeTableDataHandler } from './handlers/changeTableDataHandler'
export { changeDictHandler } from './handlers/changeDictHandler'
export { changeDataPointHandler } from './handlers/changeDataPointHandler'
export { changeSystemSettingHandler } from './handlers/changeSystemSettingHandler'
export { changeUserHandler } from './handlers/changeUserHandler'
export { callFlowHandler } from './handlers/callFlowHandler'
export { executeCommandHandler } from './handlers/executeCommandHandler'
export { sendRequestHandler } from './handlers/sendRequestHandler'

// ============== 动作处理器注册表 ==============

import {
  pageJumpHandler,
  changeVarHandler,
  changeTableDataHandler,
  changeDictHandler,
  changeDataPointHandler,
  changeSystemSettingHandler,
  changeUserHandler,
  callFlowHandler,
  executeCommandHandler,
  sendRequestHandler,
} from './handlers'

export const actionHandlers: Record<string, ActionHandler> = {
  pageJump: pageJumpHandler,
  changeVar: changeVarHandler,
  changeTableData: changeTableDataHandler,
  changeDict: changeDictHandler,
  changeDataPoint: changeDataPointHandler,
  changeSystemSetting: changeSystemSettingHandler,
  changeUser: changeUserHandler,
  callFlow: callFlowHandler,
  executeCommand: executeCommandHandler,
  sendRequest: sendRequestHandler,
}

/**
 * 获取动作处理器
 */
export function getActionHandler(actionType: string): ActionHandler {
  return actionHandlers[actionType] || (() => ({
    success: false,
    error: '未知的动作类型',
  }))
}

/**
 * 统一的对话框状态管理
 *
 * 使用方式：
 * 1. 显示对话框：await showConfirmDialog(config)
 * 2. 手动关闭：closeConfirmDialog()
 * 3. 全局组件：<GlobalDialogs />
 */

import { atom, createStore, useAtom, useSetAtom } from 'jotai'

// 创建全局 store
const dialogStore = createStore()

// 创建 atoms
export const confirmDialogAtom = atom<{
  open: boolean
  resolve?: (value: boolean) => void
  config?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
} | null>(null)

export const formDialogAtom = atom<{
  open: boolean
  resolve?: (value: any) => void
  config?: {
    title?: string
    description?: string
    fields?: any[]
    confirmText?: string
    cancelText?: string
    initialValues?: Record<string, any>
  }
} | null>(null)

/** SchemaForm 对话框 atom */
export const schemaFormDialogAtom = atom<{
  open: boolean
  resolve?: (value: any) => void
  config?: {
    title?: string
    description?: string
    schema?: any
    formSchema?: any
    confirmText?: string
    cancelText?: string
    initialValues?: Record<string, any>
  }
} | null>(null)

// 显示确认对话框
export function showConfirmDialog(
  config?: {
    title?: string
    message?: string
    confirmText?: string
    cancelText?: string
  }
): Promise<boolean> {
  return new Promise((resolve) => {
    // 使用 store.set 设置 atom 值
    dialogStore.set(confirmDialogAtom, {
      open: true,
      resolve,
      config,
    })
  })
}

// 关闭确认对话框
export function closeConfirmDialog() {
  dialogStore.set(confirmDialogAtom, null)
}

// 显示表单对话框
export function showFormDialog(
  fields: any[],
  initialValues?: Record<string, any>,
  title?: string,
  description?: string
): Promise<Record<string, any> | null> {
  return new Promise((resolve) => {
    dialogStore.set(formDialogAtom, {
      open: true,
      resolve,
      config: {
        title,
        description,
        fields,
        confirmText: '确定',
        cancelText: '取消',
        initialValues,
      },
    })
  })
}

// 关闭表单对话框
export function closeFormDialog() {
  dialogStore.set(formDialogAtom, null)
}

// 显示 SchemaForm 对话框
export function showSchemaFormDialog(
  config?: {
    schema?: any
    initialValues?: Record<string, any>
    title?: string
    description?: string
    formSchema?: any
  }
): Promise<Record<string, any> | null> {
  return new Promise((resolve) => {
    dialogStore.set(schemaFormDialogAtom, {
      open: true,
      resolve,
      config: {
        title: config?.title,
        description: config?.description,
        schema: config?.schema,
        formSchema: config?.formSchema,
        confirmText: '确定',
        cancelText: '取消',
        initialValues: config?.initialValues,
      },
    })
  })
}

// 关闭 SchemaForm 对话框
export function closeSchemaFormDialog() {
  dialogStore.set(schemaFormDialogAtom, null)
}

// 组件使用的 hook
export function useGlobalDialogs() {
  // 指定使用 dialogStore
  const [confirmDialog] = useAtom(confirmDialogAtom, { store: dialogStore })
  const [formDialog] = useAtom(formDialogAtom, { store: dialogStore })
  const [schemaFormDialog] = useAtom(schemaFormDialogAtom, { store: dialogStore })
  const setConfirmDialog = useSetAtom(confirmDialogAtom, { store: dialogStore })
  const setFormDialog = useSetAtom(formDialogAtom, { store: dialogStore })
  const setSchemaFormDialog = useSetAtom(schemaFormDialogAtom, { store: dialogStore })

  // 处理确认对话框的确认
  const handleConfirm = () => {
    if (confirmDialog?.resolve) {
      confirmDialog.resolve(true)
      setConfirmDialog(null)
    }
  }

  // 处理确认对话框的取消
  const handleCancel = () => {
    if (confirmDialog?.resolve) {
      confirmDialog.resolve(false)
      setConfirmDialog(null)
    }
  }

  // 处理表单对话框的确认
  const handleFormConfirm = (data: any) => {
    if (formDialog?.resolve) {
      formDialog.resolve(data)
      setFormDialog(null)
    }
  }

  // 处理表单对话框的取消
  const handleFormCancel = () => {
    if (formDialog?.resolve) {
      formDialog.resolve(null)
      setFormDialog(null)
    }
  }

  // 处理 SchemaForm 对话框的确认
  const handleSchemaFormConfirm = (data: any) => {
    if (schemaFormDialog?.resolve) {
      schemaFormDialog.resolve(data)
      setSchemaFormDialog(null)
    }
  }

  // 处理 SchemaForm 对话框的取消
  const handleSchemaFormCancel = () => {
    if (schemaFormDialog?.resolve) {
      schemaFormDialog.resolve(null)
      setSchemaFormDialog(null)
    }
  }

  return {
    confirmDialog,
    formDialog,
    schemaFormDialog,
    handleConfirm,
    handleCancel,
    handleFormConfirm,
    handleFormCancel,
    handleSchemaFormConfirm,
    handleSchemaFormCancel,
  }
}
